import{_ as e,a as t,b as r,c as d}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as c,o as n,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Redundant Backup اور Read Source Switching","description":"","frontmatter":{},"headers":[],"relativePath":"ur/Other/redundant-backup-and-read-source.md","filePath":"ur/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),p={name:"ur/Other/redundant-backup-and-read-source.md"};function u(s,a,o,h,b,k){return n(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="redundant-backup-اور-read-source-switching" tabindex="-1">Redundant Backup اور Read Source Switching <a class="header-anchor" href="#redundant-backup-اور-read-source-switching" aria-label="Permalink to &quot;Redundant Backup اور Read Source Switching&quot;">​</a></h1><p>Redundant backup پہلے سے uploaded file کی ایک extra copy محفوظ کرتا ہے۔</p><p>primary file اور backup file دونوں read sources کے طور پر استعمال ہو سکتے ہیں۔ visitors کو عموماً کوئی فرق محسوس نہیں ہوتا۔ فرق صرف یہ ہے کہ file کس storage channel سے serve ہو رہی ہے۔</p><h2 id="redundant-backup-کیا-کر-سکتا-ہے" tabindex="-1">Redundant Backup کیا کر سکتا ہے <a class="header-anchor" href="#redundant-backup-کیا-کر-سکتا-ہے" aria-label="Permalink to &quot;Redundant Backup کیا کر سکتا ہے&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>extra copy store کرنا</td><td>files کو دوسرے upload channel پر backup کرتا ہے تاکہ single channel failure کا risk کم ہو۔</td></tr><tr><td>read source switch کرنا</td><td>backup successful ہونے کے بعد file reads کو primary channel اور backup channel کے درمیان switch کریں۔</td></tr><tr><td>single-file backup</td><td>file details page سے ایک file backup کریں۔</td></tr><tr><td>batch backup</td><td>admin page میں multiple files select کر کے ساتھ backup کریں۔</td></tr><tr><td>global redundant backup</td><td>Other Settings سے folder کے حساب سے files backup کریں۔</td></tr></tbody></table><h2 id="redundant-backup-entry" tabindex="-1">Redundant Backup Entry <a class="header-anchor" href="#redundant-backup-entry" aria-label="Permalink to &quot;Redundant Backup Entry&quot;">​</a></h2><p>کھولیں:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+e+'" alt="Redundant backup" loading="lazy"></p><p>یہ entry folder یا تمام files میں bulk backup شامل کرنے کے لیے بہتر ہے۔</p><p>backup channel manually منتخب کیا جا سکتا ہے، یا automatic switching منتخب کر کے ImgBed کو suitable backup channel تلاش کرنے دیں۔</p><h2 id="file-details-سے-backup" tabindex="-1">File Details سے Backup <a class="header-anchor" href="#file-details-سے-backup" aria-label="Permalink to &quot;File Details سے Backup&quot;">​</a></h2><p>admin panel میں file details page کھولیں اور backup پر کلک کریں۔</p><p><img src="'+t+'" alt="Backup in file details" loading="lazy"></p><p>یہ ایک important file کو on demand backup کرنے کے لیے بہتر ہے۔</p><p>backup successful ہونے کے بعد file details page available read sources دکھاتا ہے۔</p><h2 id="selection-سے-batch-backup" tabindex="-1">Selection سے Batch Backup <a class="header-anchor" href="#selection-سے-batch-backup" aria-label="Permalink to &quot;Selection سے Batch Backup&quot;">​</a></h2><p>admin panel میں multiple files select کریں اور batch backup چلائیں۔</p><p><img src="'+r+'" alt="Batch backup" loading="lazy"></p><p>یہ files کے group کو process کرنے کے لیے بہتر ہے۔</p><p>Selection backup، file details backup، اور Other Settings کے تحت redundant backup سب ایک ہی backup system استعمال کرتے ہیں۔ فرق صرف entry points کا ہے۔</p><h2 id="backup-کے-بعد-read-source-switch-کرنا" tabindex="-1">Backup کے بعد Read Source Switch کرنا <a class="header-anchor" href="#backup-کے-بعد-read-source-switch-کرنا" aria-label="Permalink to &quot;Backup کے بعد Read Source Switch کرنا&quot;">​</a></h2><p>backup complete ہونے کے بعد file details page read source switch کرنے دیتا ہے:</p><table tabindex="0"><thead><tr><th>Read Source</th><th>Description</th></tr></thead><tbody><tr><td>Primary channel</td><td>original upload channel سے read کرتا ہے۔</td></tr><tr><td>Backup channel</td><td>backup channel سے read کرتا ہے۔</td></tr></tbody></table><p><img src="'+d+'" alt="Switch read source after backup" loading="lazy"></p><p>visitors کو یہ جاننے کی ضرورت نہیں کہ file primary channel سے serve ہو رہی ہے یا backup channel سے۔</p><p>آپ جو read source منتخب کریں گے وہ later file access کے لیے preferred source بن جائے گا۔</p><h2 id="backup-کب-skip-ہوتا-ہے" tabindex="-1">Backup کب Skip ہوتا ہے <a class="header-anchor" href="#backup-کب-skip-ہوتا-ہے" aria-label="Permalink to &quot;Backup کب Skip ہوتا ہے&quot;">​</a></h2><p>backup کے دوران یہ cases skip ہوتے ہیں۔ یہ errors نہیں۔</p><table tabindex="0"><thead><tr><th>Case</th><th>Why It Is Skipped</th></tr></thead><tbody><tr><td>Already backed up</td><td>جس file کا backup پہلے سے ہو اسے دوبارہ backup نہیں کیا جاتا۔</td></tr><tr><td>Primary and backup channels are the same</td><td>meaningful backup کے لیے copy دوسرے channel میں ہونی چاہیے۔</td></tr><tr><td>No usable backup channel</td><td>کوئی suitable alternative channel available نہیں۔</td></tr></tbody></table><p>مختصر بات: backups دوسرے channel میں جانے چاہئیں، اور already backed-up files دوبارہ extra space consume نہیں کرتیں۔</p><h2 id="primary-channel-vs-backup-channel" tabindex="-1">Primary Channel vs Backup Channel <a class="header-anchor" href="#primary-channel-vs-backup-channel" aria-label="Permalink to &quot;Primary Channel vs Backup Channel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td>Primary channel</td><td>وہ channel جو file کے first upload میں استعمال ہوا۔</td></tr><tr><td>Backup channel</td><td>وہ channel جو redundant copy store کرتا ہے۔</td></tr><tr><td>Primary read source</td><td>file currently primary channel سے read ہو رہی ہے۔</td></tr><tr><td>Backup read source</td><td>file currently backup channel سے read ہو رہی ہے۔</td></tr></tbody></table><p>Primary اور backup read sources کا user-facing behavior ایک جیسا ہے۔</p><p>جب تک backup file available ہے، backup read source پر switch کرنے کے بعد images، videos، اور download links کام کرتے رہتے ہیں۔</p><h2 id="file-delete-ہونے-پر-کیا-ہوتا-ہے" tabindex="-1">File Delete ہونے پر کیا ہوتا ہے <a class="header-anchor" href="#file-delete-ہونے-پر-کیا-ہوتا-ہے" aria-label="Permalink to &quot;File Delete ہونے پر کیا ہوتا ہے&quot;">​</a></h2><p>file delete ہونے پر ImgBed primary file اور backup file دونوں delete کرتا ہے۔</p>',37)])])}const g=c(p,[["render",u]]);export{y as __pageData,g as default};
